    pub async fn authenticate(&mut self, optional_args: &[Value]) -> Value {
        let mut params = get_arg(optional_args, 0, Value::Map({
    let mut m = indexmap::IndexMap::new();
    m
}));
        let mut messageHash: Value = Value::Str("authenticated".to_string());
        let mut type_varqueryVariable = self.handle_market_type_and_params(Value::Str("authenticate".to_string()), &[Value::Null, params.clone()]);
        let mut type_var: Value = get_value(&type_varqueryVariable, &Value::Int(0));
        let mut query: Value = get_value(&type_varqueryVariable, &Value::Int(1));
        let mut url: Value = get_value(&get_value(&get_value(&self.urls, &Value::Str("api".to_string())), &Value::Str("ws".to_string())), &type_var);
        let mut client: Value = self.client(&[url.clone()]);
        let mut future: Value = self.safe_value(get_value(&client, &Value::Str("subscriptions".to_string())), messageHash.clone(), &[]);
        if is_equal(&future, &Value::Null) {
            let mut time: Value = self.milliseconds();
            self.check_required_credentials(&[]);
            let mut requestId: Value = self.request_id();
            let mut signData: Value = add(&self.apiKey, &to_string_val(&time));
            let mut sign: Value = self.hmac(self.encode(signData.clone()), self.encode(self.secret.clone()), Value::Str("sha512".to_string()), &[Value::Str("base64".to_string())]);
            let mut request: Value = Value::Map({
                let mut m = indexmap::IndexMap::new();
                    m.insert("method".to_string(), Value::Str("login".to_string()));
                    m.insert("id".to_string(), requestId.clone());
                    m.insert("api_key".to_string(), self.apiKey.clone());
                    m.insert("sign".to_string(), sign.clone());
                    m.insert("nonce".to_string(), time.clone());
                m
            });
            let mut message: Value = self.extend(request.clone(), &[query.clone()]);
            future = self.watch(url.clone(), messageHash.clone(), &[message.clone(), messageHash.clone()]).await;
            add_element_to_object(&mut get_value(&client, &Value::Str("subscriptions".to_string())), &messageHash, future.clone());
        }
        return future;

    Value::Null
}
